    /** 根据 compartment 数据计算节点所需的高度。 */
    function calcNodeHeight(shape: string, compartments: SysMLCompartmentData | undefined): number {
        const headerH = 44;
        const compH = 20;  // 每个 compartment 条目行高
        const labelH = 18; // compartment 标签行高
        const sepH = 2;    // 分隔线高度
        let h = headerH;

        switch (shape) {
            case 'sysml-block':
                const partCount = compartments?.parts?.length || 0;
                const valueCount = compartments?.values?.length || 0;
                const portCount = compartments?.ports?.length || 0;
                if (partCount > 0) h += sepH + labelH + partCount * compH;
                if (valueCount > 0) h += sepH + labelH + valueCount * compH;
                if (portCount > 0) h += sepH + labelH + portCount * compH;
                if (partCount === 0 && valueCount === 0 && portCount === 0) h += 24; // 最小空 compartment
                break;
            case 'sysml-requirement':
                h += sepH + labelH + compH + labelH + compH; // Id + Text
                break;
            case 'sysml-testcase':
                h += sepH + labelH + compH;
                break;
            case 'sysml-valuetype':
            case 'sysml-interface':
            case 'sysml-constraintblock':
            case 'sysml-enumeration':
            case 'sysml-constraintproperty':
                const items = (compartments as any)?.[
                    shape === 'sysml-valuetype' ? 'values' :
                    shape === 'sysml-interface' ? 'operations' :
                    shape === 'sysml-enumeration' ? 'literals' : 'parameters'
                ] as any[] | undefined;
                h += sepH + (items?.length ? items.length * compH : compH);
                break;
            case 'sysml-actor':
                h += 20;
                break;
            case 'sysml-package':
            case 'sysml-model':
                h = 60; // 固定高度（标签 + 主体）
                break;
            case 'sysml-comment':
                h = 50;
                break;
            default:
                h += 24;
                break;
        }
        return Math.max(h, 60);
    }

    /** 将 compartment 内容拼接为多行文本（X6 text 用 \n 换行需要 tspans，此处返回行数组供 markup 使用）。 */
    function formatCompartmentLines(items: { name: string; type?: string; direction?: string; multiplicity?: string; defaultValue?: string }[] | string[] | undefined, kind: string): string[] {
        if (!items || items.length === 0) return [''];
        if (typeof items[0] === 'string') {
            return items as string[];
        }
        return (items as any[]).map((item: any) => {
            switch (kind) {
                case 'parts': return `  ${item.name}: ${item.type}${item.multiplicity ? ' [' + item.multiplicity + ']' : ''}`;
                case 'values': return `  ${item.name}: ${item.type}${item.defaultValue ? ' = ' + item.defaultValue : ''}`;
                case 'ports': return `  ${item.name}: ${item.direction || 'inout'} ${item.type || ''}`;
                case 'operations': return `  ${item.name}(${item.params || ''}): ${item.returnType || 'void'}`;
                case 'parameters': return `  ${item.name}: ${item.type}${item.direction ? ' [' + item.direction + ']' : ''}`;
                default: return `  ${item.name}`;
            }
        });
    }

    /** 根据 diagramType 生成 Stencil 分组。 */
    function buildStencilGroups(diagramType: string): { groups: any[]; patterns: any[] } {
        const groups: any[] = [];
        const filteredPatterns = patterns.filter(p => p.diagram === diagramType || p.diagram === 'ALL');

        const labelMap: Record<string, string> = {
            BDD: '块定义图元素', IBD: '内部块图元素', REQ: '需求图元素',
            PAR: '参数图元素', PKG: '包图元素',
        };

        groups.push({
            title: labelMap[diagramType] || 'SysML 元素',
            name: diagramType.toLowerCase(),
            collapsable: false,
            layoutOptions: { rowHeight: 40 },
        });

        return { groups, patterns: filteredPatterns };
    }

